class BookMyShow {

    int n, m;
    int[] rows;

    public BookMyShow(int n, int m) {
        this.n = n;
        this.m = m;
        rows = new int[n];
        Arrays.fill(rows, m);
    }

    public int[] gather(int k, int maxRow) {
        for (int i = 0; i <= maxRow; i++) {
            if (rows[i] >= k) {
                rows[i] -= k;
                return new int[] {i, rows[i]};
            }
        }
        return new int[] {};
    }

    public boolean scatter(int k, int maxRow) {
        for (int i = 0; i <= maxRow; i++) {
            if (rows[i] >= k) {
                rows[i] -= k;
                return true;
            }
        }
        return false;
    }
}
```

